        </div>
        </div>
    </div>
</template>

<script>
import BackgroundBeams from "./components/ui/BackgroundBeams.vue";
import DOMPurify from "dompurify";
import {
    AlertCircle,
    Check,
    Download,
    Edit2,
    FileText,
    FileVideo,
    FolderPlus,
    GripVertical,
    History,
    Layers,
    ListOrdered,
    Play,
    Plus,
    RefreshCw,
    Settings,
    Trash2,
    Upload,
    Video,
    X,
    createIcons
} from "lucide";
import { marked } from "marked";

const VALID_VIDEO_EXTENSIONS = new Set([
    "mp4", "avi", "mov", "mkv", "wmv", "flv", "webm", "m4v", "mpg", "mpeg", "3gp", "ts", "m2ts"
]);

const WEB_SEARCH_ERROR_HINTS = ["toolnotopen", "web search", "\u8054\u7f51\u641c\u7d22"];
const DEFAULT_UPLOAD_CHUNK_SIZE = 8 * 1024 * 1024;
const UPLOAD_RESUME_KEY_PREFIX = "video-upload-resume-v1";
const PROGRESS_STAGE_LABELS = {
    prepare: "准备中",
    upload: "上传中",
    subtitle: "字幕识别",
    analysis: "内容分析",
    screenshots: "截图生成",
    vision: "视觉增强",
    document: "文档生成",
    pdf: "PDF 生成",
    done: "已完成",
    failed: "失败"
};
const LUCIDE_ICON_SET = {
    AlertCircle,
    Check,
    Download,
    Edit2,
    FileText,
    FileVideo,
    FolderPlus,
    GripVertical,
    History,
    Layers,
    ListOrdered,
    Play,
    Plus,
    RefreshCw,
    Settings,
    Trash2,
    Upload,
    Video,
    X
};

const basename = (pathValue) => {
    if (!pathValue) {
        return "";
    }
    const parts = String(pathValue).split(/[\\/]/).filter(Boolean);
    return parts.length > 0 ? parts[parts.length - 1] : "";
};

const isValidVideo = (filename) => {
    const ext = String(filename || "").split(".").pop().toLowerCase();
    return VALID_VIDEO_EXTENSIONS.has(ext);
};

const clone = (value) => JSON.parse(JSON.stringify(value));

export default {
    components: {
        BackgroundBeams
    },
    data() {
        return {
            apiKey: "",
            whisperModel: "base",
            maxVision: 10,
            useVideo: false,
            webSearch: false,
            fps: 1,

            isAnalyzing: false,
            loadingHistory: false,
            savingSteps: false,

            batchFiles: [],

            resultData: null,
            batchResultData: null,
            history: [],

            isEditMode: false,
            editedSteps: [],
            dragIndex: null,
            dragOverIndex: null,

            batchDragOver: false,

            progressVisible: false,
            progressTitle: "处理中...",
            progressText: "请稍候",
            progressBoard: {
                mode: "",
                percent: 0,
                stage: "",
                total: 0,
                current: 0,
                success: 0,
                failed: 0,
                currentFile: ""
            },

            errorMessage: "",
            showErrorToast: false,
            errorTimer: null,

            iconFrame: null,
            batchProgressTimer: null,
            singleProgressTimer: null
        };
    },

    computed: {
        canAnalyze() {
            if (this.isAnalyzing) {
                return false;
            }
            return this.batchFiles.length > 0;
        },

        analyzeButtonText() {
            if (this.isAnalyzing) {
                return this.batchFiles.length === 1 ? "单文件处理中..." : "批量处理中...";
            }
            return this.batchFiles.length === 1 ? "开始单文件分析" : "开始分析";
        },

        hasSingleResult() {
            return Boolean(this.resultData);
        },

        hasBatchResult() {
            return Boolean(this.batchResultData);
        },

        hasAnyResult() {
            return this.hasSingleResult || this.hasBatchResult;
        },

        progressModeText() {
            const mode = String(this.progressBoard.mode || "");
            if (mode === "upload") {
                return "上传进度";
            }
            if (mode === "single") {
                return "单文件分析";
            }
            if (mode === "batch") {
                return "批量分析";
            }
            return "任务进度";
        },

        progressBarPercent() {
            const value = Number(this.progressBoard.percent);
            if (!Number.isFinite(value)) {
                return 0;
            }
            return Math.min(100, Math.max(0, Math.round(value)));
        },

        progressPercentText() {
            return `${this.progressBarPercent}%`;
        },

        progressCountText() {
            const total = Number(this.progressBoard.total) || 0;
            if (total <= 0) {
                return "";
            }
            const current = Math.min(Math.max(Number(this.progressBoard.current) || 0, 0), total);
            return `进度 ${current}/${total}`;
        },

        progressResultText() {
            const success = Math.max(0, Number(this.progressBoard.success) || 0);
            const failed = Math.max(0, Number(this.progressBoard.failed) || 0);
            if (success <= 0 && failed <= 0) {
                return "";
            }
            return `成功 ${success} · 失败 ${failed}`;
        },

        progressStageText() {
            const stage = String(this.progressBoard.stage || "").trim().toLowerCase();
            if (!stage) {
                return "";
            }
            return PROGRESS_STAGE_LABELS[stage] || stage;
        },

        batchUploadClass() {
            return {
                dragover: this.batchDragOver
            };
        },

        batchSummary() {
            return this.batchResultData?.summary || { total: 0, success: 0, failed: 0 };
        },

        batchDownloadDisabled() {
            return (this.batchResultData?.results || []).every((item) => !item.success);
        },

        renderedMarkdown() {
            if (!this.resultData?.markdown) {
                return "";
            }

            const outputDirName = basename(this.resultData.output_dir);
            const baseUrl = outputDirName ? `/output/${encodeURIComponent(outputDirName)}/` : "";

            const markdownText = String(this.resultData.markdown).replace(
                /!\[(.*?)\]\((images\/.*?)\)/g,
                (_match, alt, imgPath) => `![${alt}](${baseUrl}${imgPath})`
            );

            const rawHtml = marked.parse(markdownText, {
                gfm: true,
                breaks: true
            });

            return DOMPurify.sanitize(rawHtml);
        }
    },

    mounted() {
        this.renderIcons();
        this.loadHistory();
    },

    updated() {
        this.renderIcons();
    },

    beforeUnmount() {
        this.stopBatchProgressPolling();
        this.stopSingleProgressPolling();

        if (this.errorTimer) {
            clearTimeout(this.errorTimer);
        }
        if (this.iconFrame) {
            cancelAnimationFrame(this.iconFrame);
        }
    },

    methods: {
        resetProgressBoard() {
            this.progressBoard = {
                mode: "",
                percent: 0,
                stage: "",
                total: 0,
                current: 0,
                success: 0,
                failed: 0,
                currentFile: ""
            };
        },

        updateProgressBoard(patch = {}) {
            const next = {
                ...this.progressBoard,
                ...patch
            };
            const percent = Number(next.percent);
            next.percent = Number.isFinite(percent)
                ? Math.min(100, Math.max(0, percent))
                : 0;
            next.total = Math.max(0, Number(next.total) || 0);
            next.current = Math.max(0, Number(next.current) || 0);
            next.success = Math.max(0, Number(next.success) || 0);
            next.failed = Math.max(0, Number(next.failed) || 0);
            next.currentFile = String(next.currentFile || "");
            this.progressBoard = next;
        },

        getStageProgress(stage) {
            const normalized = String(stage || "").trim().toLowerCase();
            if (!normalized) {
                return 0;
            }
            const mapping = {
                prepare: 8,
                upload: 35,
                subtitle: 28,
                analysis: 55,
                screenshots: 75,
                vision: 84,
                document: 90,
                pdf: 96,
                done: 100,
                failed: 100
            };
            return mapping[normalized] ?? 0;
        },

        countBatchStatus() {
            let success = 0;
            let failed = 0;
            this.batchFiles.forEach((item) => {
                if (item.status === "success") {
                    success += 1;
                } else if (item.status === "failed") {
                    failed += 1;
                }
            });
            return { success, failed };
        },

        renderIcons() {
            if (this.iconFrame) {
                cancelAnimationFrame(this.iconFrame);
            }
            this.iconFrame = requestAnimationFrame(() => createIcons({ icons: LUCIDE_ICON_SET }));
        },

        showProgress(title, text) {
            this.progressTitle = title || "处理中...";
            this.progressText = text || "请稍候";
            this.resetProgressBoard();
            this.progressVisible = true;
        },

        hideProgress() {
            this.progressVisible = false;
            this.resetProgressBoard();
        },

        showError(message) {
            this.errorMessage = message || "操作失败";
            this.showErrorToast = true;

            if (this.errorTimer) {
                clearTimeout(this.errorTimer);
            }
            this.errorTimer = setTimeout(() => {
                this.showErrorToast = false;
            }, 5000);
        },

        async fetchJson(url, options = {}) {
            const response = await fetch(url, options);
            const data = await response.json().catch(() => ({}));

            if (!response.ok || data.error) {
                throw new Error(data.error || `请求失败 (${response.status})`);
            }

            return data;
        },

        async fetchBlob(url, options = {}) {
            const response = await fetch(url, options);
            if (!response.ok) {
                let message = `下载失败 (${response.status})`;
                try {
                    const data = await response.json();
                    if (data?.error) {
                        message = data.error;
                    }
                } catch (_error) {
                    // ignore json parse failure
                }
                throw new Error(message);
            }
            return response.blob();
        },

        triggerBatchSelect() {
            this.$refs.batchFileInput?.click();
        },

        async handleBatchSelect(event) {
            const files = event?.target?.files;
            if (!files || files.length === 0) {
                return;
            }
            await this.uploadBatchFiles(files);
            event.target.value = "";
        },

        async handleBatchDrop(event) {
            this.batchDragOver = false;
            const files = event?.dataTransfer?.files;
            if (!files || files.length === 0) {
                return;
            }
            await this.uploadBatchFiles(files);
        },

        buildUploadResumeKey(file) {
            const filename = String(file?.name || "");
            const size = Number(file?.size || 0);
            const lastModified = Number(file?.lastModified || 0);
            return `${UPLOAD_RESUME_KEY_PREFIX}:${filename}:${size}:${lastModified}`;
        },

        updateChunkUploadProgress(fileName, fileIndex, totalFiles, chunkIndex, totalChunks) {
            this.progressText = `正在上传 ${fileName}（文件 ${fileIndex}/${totalFiles}，分片 ${chunkIndex}/${totalChunks}）`;
            const safeTotalFiles = Math.max(1, Number(totalFiles) || 1);
            const safeTotalChunks = Math.max(1, Number(totalChunks) || 1);
            const safeChunkIndex = Math.min(Math.max(Number(chunkIndex) || 0, 0), safeTotalChunks);
            const completedFiles = Math.max(0, (Number(fileIndex) || 1) - 1);
            const percent = ((completedFiles + safeChunkIndex / safeTotalChunks) / safeTotalFiles) * 100;
            this.updateProgressBoard({
                mode: "upload",
                stage: "upload",
                total: safeTotalFiles,
                current: Math.min(Number(fileIndex) || 1, safeTotalFiles),
                currentFile: fileName,
                percent: Math.min(99, percent)
            });
        },

        async uploadSingleFileWithResume(file, fileIndex, totalFiles) {
            const resumeKey = this.buildUploadResumeKey(file);
            let uploadId = "";
            try {
                uploadId = window.localStorage.getItem(resumeKey) || "";
            } catch (_error) {
                uploadId = "";
            }

            const initPayload = {
                filename: file.name,
                total_size: file.size,
                chunk_size: DEFAULT_UPLOAD_CHUNK_SIZE,
                upload_id: uploadId,
                file_key: resumeKey
            };

            const initData = await this.fetchJson("/upload_chunk_init", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(initPayload)
            });

            uploadId = String(initData.upload_id || "");
            if (!uploadId) {
                throw new Error("初始化上传会话失败");
            }

            try {
                window.localStorage.setItem(resumeKey, uploadId);
            } catch (_error) {
                // ignore localStorage quota/availability errors
            }

            const chunkSize = Number(initData.chunk_size) || DEFAULT_UPLOAD_CHUNK_SIZE;
            const totalChunks = Number(initData.total_chunks) || 1;
            const receivedChunks = new Set(
                Array.isArray(initData.received_chunks)
                    ? initData.received_chunks.map((item) => Number(item))
                    : []
            );
            this.updateChunkUploadProgress(
                file.name,
                fileIndex,
                totalFiles,
                Math.min(receivedChunks.size, totalChunks),
                totalChunks
            );

            for (let chunkIndex = 0; chunkIndex < totalChunks; chunkIndex += 1) {
                if (receivedChunks.has(chunkIndex)) {
                    continue;
                }

                const start = chunkIndex * chunkSize;
                const end = Math.min(file.size, start + chunkSize);
                const chunkBlob = file.slice(start, end);

                const formData = new FormData();
                formData.append("upload_id", uploadId);
                formData.append("chunk_index", String(chunkIndex));
                formData.append("chunk", chunkBlob);

                this.updateChunkUploadProgress(file.name, fileIndex, totalFiles, chunkIndex + 1, totalChunks);
                await this.fetchJson("/upload_chunk", {
                    method: "POST",
                    body: formData
                });
            }

            this.progressText = `正在合并 ${file.name}（文件 ${fileIndex}/${totalFiles}）...`;
            this.updateProgressBoard({
                stage: "done",
                currentFile: file.name,
                percent: Math.min(
                    99,
                    (((Math.max(1, Number(fileIndex) || 1)) / Math.max(1, Number(totalFiles) || 1)) * 100)
                )
            });
            const finalized = await this.fetchJson("/upload_chunk_finalize", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ upload_id: uploadId })
            });

            try {
                window.localStorage.removeItem(resumeKey);
            } catch (_error) {
                // ignore localStorage errors
            }

            return finalized;
        },

        async uploadBatchFiles(fileList) {
            const files = Array.from(fileList || []).filter((file) => isValidVideo(file.name));
            if (files.length === 0) {
                this.showError("没有可用的视频文件，请检查格式");
                return;
            }

            this.showProgress("上传中", "正在上传视频文件（支持断点续传）...");
            this.updateProgressBoard({
                mode: "upload",
                stage: "prepare",
                total: files.length,
                current: 0,
                success: 0,
                failed: 0,
                percent: 0
            });
            try {
                const uploadedItems = [];
                const errors = [];

                for (let idx = 0; idx < files.length; idx += 1) {
                    const file = files[idx];
                    try {
                        const uploaded = await this.uploadSingleFileWithResume(file, idx + 1, files.length);
                        uploadedItems.push({
                            filename: uploaded.filename,
                            filepath: uploaded.filepath,
                            status: "pending",
                            error: ""
                        });
                        const successCount = uploadedItems.length;
                        const failedCount = errors.length;
                        const completedCount = successCount + failedCount;
                        this.updateProgressBoard({
                            mode: "upload",
                            stage: completedCount >= files.length ? "done" : "upload",
                            total: files.length,
                            current: completedCount,
                            success: successCount,
                            failed: failedCount,
                            currentFile: file.name,
                            percent: completedCount >= files.length
                                ? 100
                                : Math.min(99, (completedCount / files.length) * 100)
                        });
                    } catch (error) {
                        errors.push(`${file.name}: ${error.message}`);
                        const successCount = uploadedItems.length;
                        const failedCount = errors.length;
                        const completedCount = successCount + failedCount;
                        this.updateProgressBoard({
                            mode: "upload",
                            stage: "failed",
                            total: files.length,
                            current: completedCount,
                            success: successCount,
                            failed: failedCount,
                            currentFile: file.name,
                            percent: completedCount >= files.length
                                ? 100
                                : Math.min(99, (completedCount / files.length) * 100)
                        });
                    }
                }

                if (uploadedItems.length > 0) {
                    this.batchFiles = [...this.batchFiles, ...uploadedItems];
                }
                if (errors.length > 0) {
                    this.showError(errors.join("；"));
                }
            } catch (error) {
                this.showError(`批量上传失败: ${error.message}`);
            } finally {
                this.hideProgress();
            }
        },

        clearBatchFiles() {
            this.batchFiles = [];
        },

        removeBatchFile(index) {
            if (this.batchFiles.length <= 1) {
                return;
            }
            this.batchFiles.splice(index, 1);
        },

        async revealResultsGrid() {
            await this.$nextTick();
            const target = Array.isArray(this.$refs.resultsGrid)
                ? this.$refs.resultsGrid[0]
                : this.$refs.resultsGrid;
            if (!target || typeof target.scrollIntoView !== "function") {
                return;
            }
            target.scrollIntoView({ behavior: "smooth", block: "start" });
        },

        async startAnalyze() {
            if (!this.apiKey) {
                this.showError("请输入 ARK API Key");
                return;
            }
            if (this.batchFiles.length === 1) {
                await this.analyzeSingle();
                return;
            }
            await this.analyzeBatch();
        },

        startBatchProgressPolling() {
            this.stopBatchProgressPolling();
            this.pullBatchProgress();
            this.batchProgressTimer = setInterval(() => {
                this.pullBatchProgress();
            }, 1200);
        },

        stopBatchProgressPolling() {
            if (!this.batchProgressTimer) {
                return;
            }
            clearInterval(this.batchProgressTimer);
            this.batchProgressTimer = null;
        },

        startSingleProgressPolling() {
            this.stopSingleProgressPolling();
            this.pullSingleProgress();
            this.singleProgressTimer = setInterval(() => {
                this.pullSingleProgress();
            }, 1200);
        },

        stopSingleProgressPolling() {
            if (!this.singleProgressTimer) {
                return;
            }
            clearInterval(this.singleProgressTimer);
            this.singleProgressTimer = null;
        },

        buildSingleProgressMessage(progress) {
            const currentFile = String(progress?.current_file || "").trim();
            const stageMessage = String(progress?.message || "").trim()
                || "\u6b63\u5728\u5206\u6790\u89c6\u9891\uff0c\u8bf7\u7a0d\u5019...";
            const filePart = currentFile ? `\u5f53\u524d: ${currentFile}` : "";
            return [stageMessage, filePart].filter(Boolean).join(" | ");
        },

        async pullSingleProgress() {
            try {
                const progress = await this.fetchJson("/single_progress");
                const currentFile = String(progress.current_file || "");
                const status = String(progress.status || "").trim().toLowerCase();
                const stage = String(progress.stage || "").trim().toLowerCase();
                const stagePercent = this.getStageProgress(stage);
                const isDone = status === "completed" || stage === "done";
                const isFailed = status === "failed" || stage === "failed";
                const percent = isDone || isFailed ? 100 : stagePercent;

                if (this.progressVisible) {
                    this.progressText = this.buildSingleProgressMessage(progress);
                }

                this.updateProgressBoard({
                    mode: "single",
                    stage,
                    total: 1,
                    current: isDone || isFailed ? 1 : 0,
                    success: isDone ? 1 : 0,
                    failed: isFailed ? 1 : 0,
                    currentFile,
                    percent
                });

                if (!currentFile) {
                    return;
                }

                this.batchFiles = this.batchFiles.map((item) => {
                    if (item.status === "success" || item.status === "failed") {
                        return item;
                    }
                    if (item.filename === currentFile) {
                        return { ...item, status: "processing" };
                    }
                    return item;
                });
            } catch (_error) {
                // ignore polling failures
            }
        },

        buildProgressMessage(progress) {
            const total = Number(progress?.total) || this.batchFiles.length;
            const current = Number(progress?.current) || 0;
            const currentFile = String(progress?.current_file || "").trim();
            const stageMessage = String(progress?.message || "").trim()
                || "\u6b63\u5728\u9010\u4e2a\u5206\u6790\u89c6\u9891\uff0c\u8bf7\u7a0d\u5019...";

            const progressPart = total > 0
                ? `\u8fdb\u5ea6 ${Math.min(Math.max(current, 0), total)}/${total}`
                : "";
            const filePart = currentFile ? `\u5f53\u524d: ${currentFile}` : "";
            return [stageMessage, progressPart, filePart].filter(Boolean).join(" | ");
        },

        async pullBatchProgress() {
            try {
                const progress = await this.fetchJson("/batch_progress");
                const currentFile = String(progress.current_file || "");
                const status = String(progress.status || "").trim().toLowerCase();
                const stage = String(progress.stage || "").trim().toLowerCase();
                const total = Number(progress.total) || this.batchFiles.length;
                const current = Number(progress.current) || 0;
                const stagePercent = this.getStageProgress(stage);
                const { success, failed } = this.countBatchStatus();
                let percent = 0;
                if (total > 0) {
                    const doneFiles = Math.max(0, current - 1);
                    percent = ((doneFiles + stagePercent / 100) / total) * 100;
                }
                if (status === "completed" || stage === "done") {
                    percent = 100;
                } else {
                    percent = Math.min(99, percent);
                }

                if (this.progressVisible) {
                    this.progressText = this.buildProgressMessage(progress);
                }

                this.updateProgressBoard({
                    mode: "batch",
                    stage,
                    total,
                    current: Math.min(Math.max(current, 0), Math.max(total, 0)),
                    success,
                    failed,
                    currentFile,
                    percent
                });

                if (!currentFile) {
                    return;
                }

                this.batchFiles = this.batchFiles.map((item) => {
                    if (item.status === "success" || item.status === "failed") {
                        return item;
                    }
                    if (item.filename === currentFile) {
                        return { ...item, status: "processing" };
                    }
                    return item;
                });
            } catch (_error) {
                // ignore polling failures
            }
        },

        async analyzeSingle() {
            if (this.batchFiles.length === 0) {
                this.showError("请先上传视频文件");
                return;
            }
            if (this.batchFiles.length > 1) {
                await this.analyzeBatch();
                return;
            }

            const singleFile = this.batchFiles[0];
            if (!singleFile?.filepath) {
                this.showError("文件路径无效，请重新上传");
                return;
            }

            this.batchFiles = this.batchFiles.map((item) => ({
                ...item,
                status: "pending",
                error: ""
            }));

            this.stopBatchProgressPolling();
            this.isAnalyzing = true;
            this.showProgress("单文件处理中", "正在分析视频，请稍候...");
            this.updateProgressBoard({
                mode: "single",
                stage: "prepare",
                total: 1,
                current: 0,
                success: 0,
                failed: 0,
                currentFile: singleFile.filename || "",
                percent: 5
            });
            this.startSingleProgressPolling();
            let shouldRevealResults = false;

            try {
                const data = await this.fetchJson("/analyze", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        api_key: this.apiKey,
                        filepath: singleFile.filepath,
                        whisper_model: this.whisperModel,
                        use_video: this.useVideo,
                        web_search: this.webSearch,
                        max_vision: this.maxVision,
                        fps: this.fps
                    })
                });

                this.batchFiles = this.batchFiles.map((item, index) => {
                    if (index !== 0) {
                        return item;
                    }
                    return {
                        ...item,
                        status: "success",
                        error: ""
                    };
                });

                this.resultData = data;
                this.batchResultData = null;
                this.isEditMode = false;
                this.editedSteps = [];
                this.updateProgressBoard({
                    mode: "single",
                    stage: "done",
                    total: 1,
                    current: 1,
                    success: 1,
                    failed: 0,
                    currentFile: singleFile.filename || "",
                    percent: 100
                });
                shouldRevealResults = true;
                await this.loadHistory();
            } catch (error) {
                const message = String(error?.message || "");
                if (this.isWebSearchError(message)) {
                    this.webSearch = false;
                }
                this.batchFiles = this.batchFiles.map((item, index) => {
                    if (index !== 0) {
                        return item;
                    }
                    return {
                        ...item,
                        status: "failed",
                        error: message
                    };
                });
                this.updateProgressBoard({
                    mode: "single",
                    stage: "failed",
                    total: 1,
                    current: 1,
                    success: 0,
                    failed: 1,
                    currentFile: singleFile.filename || "",
                    percent: 100
                });
                this.showError(`单文件分析失败: ${message}`);
            } finally {
                this.stopSingleProgressPolling();
                this.isAnalyzing = false;
                this.hideProgress();
                if (shouldRevealResults) {
                    await this.revealResultsGrid();
                }
            }
        },

        async analyzeBatch() {
            if (this.batchFiles.length === 0) {
                this.showError("请先上传批量视频文件");
                return;
            }
            if (this.batchFiles.length === 1) {
                await this.analyzeSingle();
                return;
            }

            this.batchFiles = this.batchFiles.map((item) => ({
                ...item,
                status: "pending",
                error: ""
            }));

            this.stopSingleProgressPolling();
            this.isAnalyzing = true;
            this.showProgress("批量处理中", "正在逐个分析视频，请稍候...");
            this.updateProgressBoard({
                mode: "batch",
                stage: "prepare",
                total: this.batchFiles.length,
                current: 0,
                success: 0,
                failed: 0,
                percent: 0
            });
            this.startBatchProgressPolling();
            let shouldRevealResults = false;

            try {
                const data = await this.fetchJson("/analyze_batch", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        api_key: this.apiKey,
                        filepaths: this.batchFiles.map((item) => item.filepath),
                        whisper_model: this.whisperModel,
                        use_video: this.useVideo,
                        web_search: this.webSearch,
                        max_vision: this.maxVision,
                        fps: this.fps
                    })
                });

                const results = data.results || [];
                this.batchFiles = this.batchFiles.map((item, index) => {
                    const result = results[index];
                    if (!result) {
                        return item;
                    }
                    return {
                        ...item,
                        status: result.success ? "success" : "failed",
                        error: result.error || ""
                    };
                });

                if (results.some((item) => !item.success && this.isWebSearchError(item.error))) {
                    this.webSearch = false;
                }

                this.batchResultData = data;
                this.resultData = null;
                this.isEditMode = false;
                this.editedSteps = [];
                this.updateProgressBoard({
                    mode: "batch",
                    stage: "done",
                    total: Number(data?.summary?.total) || this.batchFiles.length,
                    current: Number(data?.summary?.total) || this.batchFiles.length,
                    success: Number(data?.summary?.success) || 0,
                    failed: Number(data?.summary?.failed) || 0,
                    currentFile: "",
                    percent: 100
                });
                shouldRevealResults = true;
                await this.loadHistory();
            } catch (error) {
                const { success, failed } = this.countBatchStatus();
                this.updateProgressBoard({
                    mode: "batch",
                    stage: "failed",
                    total: this.batchFiles.length,
                    current: success + failed,
                    success,
                    failed,
                    percent: 100
                });
                this.showError(`批量分析失败: ${error.message}`);
            } finally {
                this.stopBatchProgressPolling();
                this.isAnalyzing = false;
                this.hideProgress();
                if (shouldRevealResults) {
                    await this.revealResultsGrid();
                }
            }
        },

        isWebSearchError(errorMessage) {
            const normalized = String(errorMessage || "").toLowerCase();
            return WEB_SEARCH_ERROR_HINTS.some((hint) => normalized.includes(hint));
        },

        batchStatusText(status) {
            if (status === "success") {
                return "已完成";
            }
            if (status === "failed") {
                return "失败";
            }
            if (status === "processing") {
                return "处理中";
            }
            return "待处理";
        },

        modeBadgeClass(mode) {
            return mode === "video" ? "history-badge-video" : "history-badge-subtitle";
        },

        modeLabel(mode) {
            return mode === "video" ? "视频模式" : "字幕模式";
        },

        async loadHistory() {
            this.loadingHistory = true;
            try {
                const data = await this.fetchJson("/history");
                this.history = Array.isArray(data.history) ? data.history : [];
            } catch (error) {
                this.showError(`加载历史失败: ${error.message}`);
            } finally {
                this.loadingHistory = false;
            }
        },

        async openHistoryRecord(recordId) {
            this.showProgress("加载中", "正在读取历史记录...");
            try {
                const data = await this.fetchJson(`/history/${recordId}`);
                const record = data.record || {};
                this.resultData = {
                    steps: Array.isArray(record.steps) ? record.steps : [],
                    markdown: record.markdown || "",
                    output_dir: record.output_dir || "",
                    pdf_path: record.pdf_path || ""
                };
                this.batchResultData = null;
                this.isEditMode = false;
                this.editedSteps = [];
            } catch (error) {
                this.showError(`加载历史失败: ${error.message}`);
            } finally {
                this.hideProgress();
            }
        },

        async removeHistoryRecord(recordId) {
            if (!window.confirm("确定要删除这条历史记录吗？")) {
                return;
            }

            try {
                await this.fetchJson(`/history/${recordId}`, { method: "DELETE" });
                await this.loadHistory();
            } catch (error) {
                this.showError(`删除失败: ${error.message}`);
            }
        },

        confidenceClass(value) {
            const confidence = Number(value);
            if (confidence >= 0.7) {
                return "confidence-high";
            }
            if (confidence >= 0.4) {
                return "confidence-medium";
            }
            return "confidence-low";
        },

        confidenceLabel(value) {
            const confidence = Number(value);
            if (confidence >= 0.7) {
                return "高";
            }
            if (confidence >= 0.4) {
                return "中";
            }
            return "低";
        },

        enterEditMode() {
            if (!Array.isArray(this.resultData?.steps) || this.resultData.steps.length === 0) {
                this.showError("当前没有可编辑的步骤");
                return;
            }

            this.editedSteps = clone(this.resultData.steps).map((step, index) => ({
                ...step,
                step: index + 1,
                time: step.time || "00:00",
                title: step.title || "",
                description: step.description || ""
            }));
            this.isEditMode = true;
        },

        cancelEditMode() {
            this.isEditMode = false;
            this.editedSteps = [];
            this.dragIndex = null;
            this.dragOverIndex = null;
        },

        addStep() {
            this.editedSteps.push({
                step: this.editedSteps.length + 1,
                time: "00:00",
                title: "新步骤",
                description: "请输入步骤描述"
            });
        },

        removeEditedStep(index) {
            this.editedSteps.splice(index, 1);
            this.reindexEditedSteps();
        },

        reindexEditedSteps() {
            this.editedSteps = this.editedSteps.map((step, index) => ({
                ...step,
                step: index + 1
            }));
        },

        onStepDragStart(index) {
            this.dragIndex = index;
        },

        onStepDragOver(index) {
            this.dragOverIndex = index;
        },

        onStepDrop(index) {
            if (this.dragIndex === null || this.dragIndex === index) {
                this.dragOverIndex = null;
                return;
            }

            const [moved] = this.editedSteps.splice(this.dragIndex, 1);
            if (!moved) {
                this.dragOverIndex = null;
                return;
            }

            this.editedSteps.splice(index, 0, moved);
            this.reindexEditedSteps();
            this.dragIndex = null;
            this.dragOverIndex = null;
        },

        onStepDragEnd() {
            this.dragIndex = null;
            this.dragOverIndex = null;
        },

        async saveEditedSteps() {
            if (!this.apiKey) {
                this.showError("请输入 ARK API Key");
                return;
            }
            if (!this.resultData?.output_dir) {
                this.showError("缺少输出目录信息");
                return;
            }

            this.savingSteps = true;
            this.showProgress("重新生成中", "根据编辑后的步骤生成新文档...");
            try {
                const data = await this.fetchJson("/regenerate", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        api_key: this.apiKey,
                        steps: this.editedSteps,
                        output_dir: this.resultData.output_dir,
                        web_search: this.webSearch
                    })
                });

                this.resultData = data;
                this.isEditMode = false;
                this.editedSteps = [];
            } catch (error) {
                this.showError(`重新生成失败: ${error.message}`);
            } finally {
                this.savingSteps = false;
                this.hideProgress();
            }
        },

        triggerDownload(blob, filename) {
            const url = URL.createObjectURL(blob);
            const anchor = document.createElement("a");
            anchor.href = url;
            anchor.download = filename;
            anchor.click();
            URL.revokeObjectURL(url);
        },

        async downloadSingleZip() {
            const outputDirName = basename(this.resultData?.output_dir);
            if (!outputDirName) {
                this.showError("没有可下载的结果");
                return;
            }

            try {
                const blob = await this.fetchBlob(`/download_zip/${encodeURIComponent(outputDirName)}`);
                this.triggerDownload(blob, `${outputDirName}.zip`);
            } catch (error) {
                this.showError(`下载失败: ${error.message}`);
            }
        },

        async downloadSingleFromBatch(outputDir, filename) {
            const outputDirName = basename(outputDir);
            if (!outputDirName) {
                this.showError("下载路径无效");
                return;
            }

            try {
                const blob = await this.fetchBlob(`/download_zip/${encodeURIComponent(outputDirName)}`);
                const baseName = basename(filename).replace(/\.[^/.]+$/, "") || outputDirName;
                this.triggerDownload(blob, `${baseName}.zip`);
            } catch (error) {
                this.showError(`下载失败: ${error.message}`);
            }
        },

        async downloadBatchZip() {
            const outputDirs = (this.batchResultData?.results || [])
                .filter((item) => item.success && item.output_dir)
                .map((item) => item.output_dir);

            if (outputDirs.length === 0) {
                this.showError("没有可下载的批量结果");
                return;
            }

            try {
                const blob = await this.fetchBlob("/download_batch_zip", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ output_dirs: outputDirs })
                });
                this.triggerDownload(blob, "batch_results.zip");
            } catch (error) {
                this.showError(`下载失败: ${error.message}`);
            }
        }
    }
};
</script>
